#include <iostream>

using namespace std;

int main()
{
    int age = 25;
    int *agePtr = &age;

    cout << "Value of age: " << age << endl;
    cout << "Value via pointer: " << *agePtr << endl;

    return 0;
}

#include <iostream>

using namespace std;

int main()
{
    int age = 25;
    int *agePtr = &age;

    *agePtr = 30; // changes age itself, through the pointer

    cout << age << endl;

    return 0;
}

